mapper.select:
SELECT a.id, a.name, a.remark, a.protocol, a.port, a.path, a.environment_id environmentId, a.server_id serverId, a.object_id objectId, a.object_key objectKey, a.create_id createId, CONVERT(a.create_time, char) createTime, a.last_update_id lastUpdateId, CONVERT(a.last_update_time, char) lastUpdateTime FROM auto_microservice a
AND a.tenant_id = #{tenantId}
AND a.object_id = #{objectId}
AND a.object_key = #{objectKey}
${sqlExtract}
AND a.`name` like '%${keyword}%'
ORDER BY a.create_time DESC
